              <Button
                variant="secondary"
                size="md"
                fullWidth
                disabled
                className="opacity-80"
                icon={<CheckCircle2 className="w-4 h-4 text-emerald-500" />}
              >
                Connected
              </Button>
              <Button
                variant="danger"
                size="md"
