import { useState, useEffect } from 'react';
import { Search, ShieldAlert, CheckCircle2, Clock, Trash2, RefreshCw, Zap, KeyRound, Mail as MailIcon } from 'lucide-react';
import { supabase } from '../../lib/supabaseClient';
import { setConnectionsEnabled } from '../../lib/connections';
import { useToast } from '../../context/ToastContext';
import { useConfirmDialog } from '../../context/ConfirmDialogContext';

export default function AdminAccess() {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [search, setSearch] = useState('');
  const [filter, setFilter] = useState('all');
  const [updatingRoleId, setUpdatingRoleId] = useState('');
  const toast = useToast();
  const { confirm } = useConfirmDialog();

  const fetchUsers = async () => {
    setLoading(true);
    setError('');
    const { data, error: fetchError } = await supabase
      .from('profiles')
      .select('id, name, email, phone, location, role, status, created_at, connections_enabled, temp_password_required')
      .order('created_at', { ascending: false });
    if (fetchError) {
      setError(fetchError.message);
      setUsers([]);
      toast.error(`Failed to load users: ${fetchError.message}`);
    } else {
      setUsers(data ?? []);
    }
    setLoading(false);
  };

  useEffect(() => { fetchUsers(); }, []);

  const updateStatus = async (id, status) => {
    const { error: updErr } = await supabase.from('profiles').update({ status }).eq('id', id);
    if (updErr) {
      toast.error(`Failed to update status: ${updErr.message}`);
      return;
    }
    const target = users.find((u) => u.id === id);
    setUsers(prev => prev.map(u => u.id === id ? { ...u, status } : u));
    toast.success(`${target?.name || 'User'} status set to ${status}.`);

    if (status === 'active' && target?.status === 'pending' && target?.email) {
      const { error: emailError } = await supabase.auth.signInWithOtp({
        email: target.email,
        options: { shouldCreateUser: false },
      });
      if (emailError) {
        toast.warning(`Approved, but email notification failed: ${emailError.message}`);
      } else {
        toast.info(`Approval email sent to ${target.email}.`);
      }
    }
  };

  const sendResetEmail = async (target) => {
    if (!target?.email) {
      toast.warning('No email found for this user.');
      return;
    }
    const { error: resetError } = await supabase.auth.resetPasswordForEmail(target.email, {
      redirectTo: `${window.location.origin}/login`,
    });
    if (resetError) {
      toast.error(`Failed to send reset email: ${resetError.message}`);
      return;
    }
    toast.success(`Password reset email sent to ${target.email}.`);
  };

  const setTemporaryPassword = async (target) => {
    const ok = await confirm({
      title: 'Set temporary password',
      message: `Generate a temporary password for ${target?.name || 'this user'}?`,
      confirmText: 'Generate',
      cancelText: 'Cancel',
      variant: 'warning',
    });
    if (!ok) {
      toast.warning('Temporary password action cancelled.');
      return;
    }

    const tempPassword = `Corevia-${Math.random().toString(36).slice(2, 6)}${Math.random().toString(36).slice(2, 6)}!`;
    const { error: rpcError } = await supabase.rpc('admin_set_temporary_password', {
      target_user_id: target.id,
      temporary_password: tempPassword,
    });
    if (rpcError) {
      toast.error(`Failed to set temporary password: ${rpcError.message}`);
      return;
    }

    setUsers((prev) => prev.map((u) => (u.id === target.id ? { ...u, temp_password_required: true } : u)));
    await navigator.clipboard.writeText(tempPassword);
    toast.success(`Temporary password generated and copied for ${target.name || 'user'}.`);
  };

  const updateRole = async (id, role) => {
    setUpdatingRoleId(id);
    const { error: updErr } = await supabase.from('profiles').update({ role }).eq('id', id);
    setUpdatingRoleId('');
    if (updErr) {
      toast.error(`Failed to update role: ${updErr.message}`);
      return;
    }
    const target = users.find(u => u.id === id);
    setUsers(prev => prev.map(u => u.id === id ? { ...u, role } : u));
    toast.success(`${target?.name || 'User'} role set to ${role}.`);
  };

  const toggleConnections = async (id, next) => {
    try {
      await setConnectionsEnabled(id, next);
      const target = users.find((u) => u.id === id);
      setUsers(prev => prev.map(u => u.id === id ? { ...u, connections_enabled: next } : u));
      toast.info(`${target?.name || 'User'} connections ${next ? 'enabled' : 'disabled'}.`);
    } catch (e) {
      toast.error(`Failed to toggle connections: ${e.message}`);
    }
  };

  const deleteUser = async (id) => {
    const shouldDelete = await confirm({
      title: 'Delete user',
      message: 'Are you sure you want to permanently delete this user?',
      confirmText: 'Delete',
      cancelText: 'Keep User',
      variant: 'danger',
    });
    if (!shouldDelete) {
      toast.warning('Delete action cancelled.');
      return;
    }
    const target = users.find((u) => u.id === id);
    const { error: delErr } = await supabase.from('profiles').delete().eq('id', id);
    if (delErr) {
      toast.error(`Failed to delete user: ${delErr.message}`);
      return;
    }
    setUsers(prev => prev.filter(u => u.id !== id));
    toast.success(`${target?.name || 'User'} deleted.`);
  };

  const filtered = users.filter(u => {
    const q = search.toLowerCase();
    const matchSearch =
      (u.name || '').toLowerCase().includes(q) ||
      (u.email || '').toLowerCase().includes(q) ||
      (u.location || '').toLowerCase().includes(q);
    const matchFilter = filter === 'all' || u.status === filter;
    return matchSearch && matchFilter;
  });

  const statusBadge = (status) => {
    if (status === 'active') return 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400';
    if (status === 'pending') return 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400';
    return 'bg-rose-100 text-rose-700 dark:bg-rose-900/30 dark:text-rose-400';
  };

  const statusIcon = (status) => {
    if (status === 'active') return <CheckCircle2 className="w-3 h-3" />;
    if (status === 'pending') return <Clock className="w-3 h-3" />;
    return <ShieldAlert className="w-3 h-3" />;
  };

  const pendingCount = users.filter((u) => u.status === 'pending').length;

  return (
    <div className="space-y-6">
      {pendingCount > 0 && (
        <div className="rounded-xl border border-amber-200 bg-amber-50 px-4 py-3 text-sm text-amber-800 dark:border-amber-900/50 dark:bg-amber-950/30 dark:text-amber-300">
          {pendingCount} signup request{pendingCount === 1 ? '' : 's'} pending review. Approve to activate and notify users.
        </div>
      )}

      <div className="flex flex-col sm:flex-row sm:justify-between sm:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-900 dark:text-white">Access Control</h2>
          <p className="text-slate-500 dark:text-slate-400 mt-1 text-sm">Approve signups, manage access, and reset credentials.</p>
        </div>
        <button onClick={fetchUsers} className="flex items-center gap-2 text-sm text-slate-500 dark:text-slate-400 hover:text-brand-600 dark:hover:text-brand-400 transition-colors">
          <RefreshCw className="w-4 h-4" /> Refresh
        </button>
      </div>

      <div className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl overflow-hidden shadow-sm">
        {/* Toolbar */}
        <div className="p-4 border-b border-slate-100 dark:border-slate-800 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-3 bg-slate-50 dark:bg-slate-950/50">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
            <input
              type="text"
              placeholder="Search by nameΓÇª"
              value={search}
              onChange={e => setSearch(e.target.value)}
              className="pl-9 pr-4 py-2 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg text-sm text-slate-900 dark:text-white focus:ring-brand-500 focus:border-brand-500 outline-none w-56 transition-colors"
            />
          </div>
          <div className="flex gap-2">
            {['all', 'pending', 'active', 'suspended'].map(f => (
              <button
                key={f}
                onClick={() => setFilter(f)}
                className={`px-3 py-1.5 rounded-full text-xs font-medium capitalize transition-colors ${
                  filter === f
                    ? 'bg-slate-900 dark:bg-brand-600 text-white'
                    : 'bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 hover:border-slate-300'
                }`}
              >
                {f}
              </button>
            ))}
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 dark:bg-slate-950/50 text-slate-500 dark:text-slate-400 border-b border-slate-100 dark:border-slate-800">
              <tr>
                <th className="px-6 py-3 font-semibold">User</th>
                <th className="px-6 py-3 font-semibold">Contact</th>
                <th className="px-6 py-3 font-semibold">Role</th>
                <th className="px-6 py-3 font-semibold">Status</th>
                <th className="px-6 py-3 font-semibold">Features</th>
                <th className="px-6 py-3 font-semibold">Joined</th>
                <th className="px-6 py-3 font-semibold text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
              {loading ? (
                <tr><td colSpan={7} className="px-6 py-8 text-center text-slate-400">LoadingΓÇª</td></tr>
              ) : error ? (
                <tr><td colSpan={7} className="px-6 py-8 text-center text-rose-500">{error}</td></tr>
              ) : filtered.length === 0 ? (
                <tr><td colSpan={7} className="px-6 py-8 text-center text-slate-400">No users found.</td></tr>
              ) : filtered.map((user) => (
                <tr key={user.id} className="hover:bg-slate-50 dark:hover:bg-slate-800/40 transition-colors">
                  <td className="px-6 py-4">
                    <div className="font-medium text-slate-900 dark:text-slate-200">{user.name || 'ΓÇö'}</div>
                    <div className="text-slate-400 dark:text-slate-500 text-xs font-mono">{user.id.slice(0, 8)}ΓÇª</div>
                    {user.temp_password_required && (
                      <div className="mt-1 text-[11px] font-semibold text-amber-600 dark:text-amber-400">Must change temp password</div>
                    )}
                  </td>
                  <td className="px-6 py-4">
                    <div className="text-slate-700 dark:text-slate-300 text-xs">{user.email || 'No email'}</div>
                    <div className="text-slate-400 dark:text-slate-500 text-xs">{user.phone || user.location || 'No additional details'}</div>
                  </td>
                  <td className="px-6 py-4">
                    <select
                      value={user.role || 'agent'}
                      onChange={(e) => updateRole(user.id, e.target.value)}
                      disabled={updatingRoleId === user.id}
                      className="text-xs font-medium px-2 py-1 rounded-full bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-200 capitalize border border-slate-200 dark:border-slate-700 disabled:opacity-60"
                    >
                      <option value="agent">agent</option>
                      <option value="admin">admin</option>
                    </select>
                  </td>
                  <td className="px-6 py-4">
                    <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium capitalize ${statusBadge(user.status)}`}>
                      {statusIcon(user.status)} {user.status ?? 'pending'}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    <FeatureToggle
                      label="Connections"
                      enabled={!!user.connections_enabled}
                      onChange={(next) => toggleConnections(user.id, next)}
                    />
                  </td>
                  <td className="px-6 py-4 text-slate-400 dark:text-slate-500 text-xs">
                    {new Date(user.created_at).toLocaleDateString()}
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex items-center justify-end gap-2">
                      <button
                        onClick={() => sendResetEmail(user)}
                        className="px-2.5 py-1.5 rounded-lg text-xs font-medium bg-sky-50 text-sky-700 hover:bg-sky-100 dark:bg-sky-900/20 dark:text-sky-400 dark:hover:bg-sky-900/40 transition-colors"
                        title="Send password reset email"
                      >
                        <MailIcon className="w-3.5 h-3.5 inline mr-1" /> Reset Email
                      </button>
                      <button
                        onClick={() => setTemporaryPassword(user)}
                        className="px-2.5 py-1.5 rounded-lg text-xs font-medium bg-amber-50 text-amber-700 hover:bg-amber-100 dark:bg-amber-900/20 dark:text-amber-400 dark:hover:bg-amber-900/40 transition-colors"
                        title="Generate temporary password"
                      >
                        <KeyRound className="w-3.5 h-3.5 inline mr-1" /> Temp Password
                      </button>
                      {user.status === 'pending' && (
                        <button onClick={() => updateStatus(user.id, 'active')} className="px-3 py-1.5 rounded-lg text-xs font-medium bg-emerald-50 text-emerald-700 hover:bg-emerald-100 dark:bg-emerald-900/20 dark:text-emerald-400 dark:hover:bg-emerald-900/40 transition-colors">
                          Approve
                        </button>
                      )}
                      {user.status === 'pending' && (
                        <button onClick={() => updateStatus(user.id, 'suspended')} className="px-3 py-1.5 rounded-lg text-xs font-medium bg-rose-50 text-rose-700 hover:bg-rose-100 dark:bg-rose-900/20 dark:text-rose-400 dark:hover:bg-rose-900/40 transition-colors">
                          Reject
                        </button>
                      )}
                      {user.status === 'active' && (
                        <button onClick={() => updateStatus(user.id, 'suspended')} className="px-3 py-1.5 rounded-lg text-xs font-medium bg-rose-50 text-rose-700 hover:bg-rose-100 dark:bg-rose-900/20 dark:text-rose-400 dark:hover:bg-rose-900/40 transition-colors">
                          Suspend
                        </button>
                      )}
                      {user.status === 'suspended' && (
                        <button onClick={() => updateStatus(user.id, 'active')} className="px-3 py-1.5 rounded-lg text-xs font-medium bg-emerald-50 text-emerald-700 hover:bg-emerald-100 dark:bg-emerald-900/20 dark:text-emerald-400 dark:hover:bg-emerald-900/40 transition-colors">
                          Activate
                        </button>
                      )}
                      <button onClick={() => deleteUser(user.id)} className="p-1.5 rounded-lg text-slate-300 hover:text-rose-500 dark:text-slate-600 dark:hover:text-rose-400 hover:bg-rose-50 dark:hover:bg-rose-900/20 transition-colors">
                        <Trash2 className="w-3.5 h-3.5" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

function FeatureToggle({ label, enabled, onChange }) {
  return (
    <button
      type="button"
      onClick={() => onChange(!enabled)}
      title={`${label}: ${enabled ? 'enabled' : 'disabled'} ΓÇö click to toggle`}
      className={`inline-flex items-center gap-2 px-2.5 py-1 rounded-full text-xs font-medium border transition-colors ${
        enabled
          ? 'bg-brand-50 text-brand-700 border-brand-200 dark:bg-brand-500/15 dark:text-brand-300 dark:border-brand-500/30'
          : 'bg-slate-50 text-slate-500 border-slate-200 dark:bg-slate-800 dark:text-slate-400 dark:border-slate-700'
      }`}
    >
      <span
        className={`inline-flex items-center justify-center w-6 h-3.5 rounded-full transition-colors ${
          enabled ? 'bg-brand-500' : 'bg-slate-300 dark:bg-slate-600'
        }`}
      >
        <span
          className={`w-3 h-3 rounded-full bg-white shadow transform transition-transform ${
            enabled ? 'translate-x-1.5' : '-translate-x-1.5'
          }`}
        />
      </span>
      <Zap className="w-3 h-3" />
      {label}
    </button>
  );
}

import { useEffect, useMemo, useState } from 'react';
import { Zap, Sparkles, Lock } from 'lucide-react';
import { Link } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useToast } from '../../context/ToastContext';
import { PLATFORMS } from '../../components/dashboard/connections/platforms';
import PlatformCard from '../../components/dashboard/connections/PlatformCard';
import Button from '../../components/ui/Button';
import {
  listConnections,
  setConnectionStatus,
  upsertConnection,
  getConnectionsEnabled,
} from '../../lib/connections';

export default function Connections() {
  const { user } = useAuth();
  const toast = useToast();
  const agentId = user?.id;

  const [enabled, setEnabled] = useState(!!user?.connections_enabled);
  const [rows, setRows] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let cancelled = false;
    const load = async () => {
      if (!agentId) {
        console.log("Connections: No agentId yet, waiting...");
        return;
      }
      setLoading(true);
      console.log("Connections: Loading for agentId:", agentId);
      try {
        const [flag, conns] = await Promise.all([
          getConnectionsEnabled(agentId),
          listConnections(agentId),
        ]);
        if (cancelled) return;

        const isEnabled = flag || !!user?.connections_enabled;
        console.log("Connections: isEnabled?", isEnabled, "connections count:", conns?.length);

        setEnabled(isEnabled);
        setRows(conns);
      } catch (err) {
        console.error("Connections: Failed to load data:", err);
        toast.error(`Failed to load connections: ${err.message}`);
      } finally {
        if (!cancelled) {
          setLoading(false);
          console.log("Connections: Loading finished");
        }
      }
    };
    load();
    return () => { cancelled = true; };
  }, [agentId, user?.connections_enabled]);

  const byPlatform = useMemo(() => {
    const map = {};
    for (const r of rows) map[r.platform] = r;
    return map;
  }, [rows]);

  const connectedCount = rows.filter((r) => r.status === 'connected').length;

  const handleConnect = async (platform, handle) => {
    try {
      const saved = await upsertConnection(agentId, platform, {
        handle,
        status: 'connected',
        connected_at: new Date().toISOString(),
      });
      setRows((prev) => {
        const next = prev.filter((r) => r.platform !== platform);
        next.push(saved);
        return next;
      });
      toast.success(`${platform} connected.`);
    } catch (err) {
      toast.error(`Failed to connect ${platform}: ${err.message}`);
    }
  };

  const handleDisconnect = async (platform) => {
    try {
      const saved = await setConnectionStatus(agentId, platform, 'disconnected');
      setRows((prev) => {
        const next = prev.filter((r) => r.platform !== platform);
        next.push({ ...saved, status: 'disconnected' });
        return next;
      });
      toast.warning(`${platform} disconnected.`);
    } catch (err) {
      toast.error(`Failed to disconnect ${platform}: ${err.message}`);
    }
  };

  if (!enabled) {
    return <DisabledState />;
  }

  return (
    <div className="transition-colors">
      <div className="flex flex-col sm:flex-row sm:justify-between sm:items-end mb-6 md:mb-8 gap-4">
        <div>
          <div className="inline-flex items-center gap-2 text-xs font-semibold uppercase tracking-wider text-brand-700 dark:text-brand-400 bg-brand-100 dark:bg-brand-900/30 px-2 py-1 rounded-full mb-2">
            <Sparkles className="w-3 h-3" /> Killer feature
          </div>
          <h2 className="text-2xl font-bold text-slate-900 dark:text-white">Connections</h2>
          <p className="text-slate-500 dark:text-slate-400 mt-1 text-sm max-w-xl">
            Link the channels your buyers actually use. Once connected, you can auto-reply,
            auto-post listings, and one-tap chat from every lead card ΓÇö no more copy-pasting
            Messenger links.
          </p>
        </div>
        <div className="text-right">
          <div className="text-xs text-slate-500 dark:text-slate-400">Connected channels</div>
          <div className="text-2xl font-bold text-slate-900 dark:text-white">
            {connectedCount}<span className="text-slate-400 dark:text-slate-500 text-base font-medium">/{PLATFORMS.length}</span>
          </div>
        </div>
      </div>

      {loading ? (
        <div className="text-slate-500 dark:text-slate-400 text-sm">Loading your connectionsΓÇª</div>
      ) : (
        <div className="grid gap-4 sm:grid-cols-2">
          {PLATFORMS.map((p) => (
            <PlatformCard
              key={p.id}
              platform={p}
              connection={byPlatform[p.id]}
              onConnect={handleConnect}
              onDisconnect={handleDisconnect}
            />
          ))}
        </div>
      )}

      <p className="mt-6 text-xs text-slate-400 dark:text-slate-500">
        Automation is coming soon. Connecting now pre-wires your handles so your listings and
        lead cards use them everywhere.
      </p>
    </div>
  );
}

function DisabledState() {
  return (
    <div className="max-w-lg mx-auto text-center py-16">
      <div className="w-14 h-14 rounded-2xl bg-slate-100 dark:bg-slate-800 flex items-center justify-center mx-auto mb-4">
        <Lock className="w-6 h-6 text-slate-400" />
      </div>
      <h2 className="text-xl font-bold text-slate-900 dark:text-white mb-2">
        Connections aren't turned on yet
      </h2>
      <p className="text-sm text-slate-500 dark:text-slate-400 mb-6">
        This feature links Messenger, WhatsApp, Viber and Facebook so your listings auto-route
        buyers to the right channel. Ask your admin to enable it for your account.
      </p>
      <Link to="/dashboard">
        <Button variant="secondary" icon={<Zap className="w-4 h-4" />}>
          Back to dashboard
        </Button>
      </Link>
    </div>
  );
}

